// Day Counter — weekday-based 90-day counter starting March 2, 2026
function getWeekdayDates() {
  const dates = [];
  const d = new Date('2026-03-02T00:00:00+01:00');
  while (dates.length < 90) {
    if (d.getDay() !== 0 && d.getDay() !== 6) dates.push(new Date(d));
    d.setDate(d.getDate() + 1);
  }
  return dates;
}
const weekdays = getWeekdayDates();
const now = new Date();
const todayStr = now.toISOString().split('T')[0];
let dayNum = null;
for (let i = 0; i < weekdays.length; i++) {
  if (weekdays[i].toISOString().split('T')[0] === todayStr) { dayNum = i + 1; break; }
}
const isWeekend = now.getDay() === 0 || now.getDay() === 6;
const weekNum = dayNum ? Math.ceil(dayNum / 5) : null;
// On Sunday dayNum will be null — compute weekNum from last Friday
let effectiveWeekNum = weekNum;
if (!dayNum) {
  // Find the most recent weekday
  const yesterday = new Date(now);
  yesterday.setDate(yesterday.getDate() - 1);
  const yStr = yesterday.toISOString().split('T')[0];
  for (let i = 0; i < weekdays.length; i++) {
    if (weekdays[i].toISOString().split('T')[0] <= yStr) effectiveWeekNum = Math.ceil((i + 1) / 5);
  }
}
return [{ json: { day_number: dayNum, week_num: effectiveWeekNum, is_weekend: isWeekend, date: todayStr } }];

const weekNum = $input.first().json.week_num || $('Day Counter').first().json.week_num || 1;
let phase, weeklyTarget;
if (weekNum <= 4) { phase = 1; weeklyTarget = 1000; }
else if (weekNum <= 8) { phase = 2; weeklyTarget = 5000; }
else { phase = 3; weeklyTarget = 20000; }
return [{ json: { ...$('Day Counter').first().json, revenue_phase: phase, weekly_target: weeklyTarget } }];

const logsRaw = $('Get Weekly Logs').first().json;
const logs = Array.isArray(logsRaw) ? logsRaw : [logsRaw].filter(Boolean);
const prev = $input.first().json;

const stats = {
  week_number: prev.week_num,
  revenue_phase: prev.revenue_phase,
  weekly_target: prev.weekly_target,
  days_in_week: logs.length,
  prayer_sessions: logs.reduce((s, d) => s + (d.prayer_s1?1:0) + (d.prayer_s2?1:0), 0),
  nt_chapters: logs.reduce((s, d) => s + (Array.isArray(d.nt_chapters_read) ? d.nt_chapters_read.length : 0), 0),
  book_pages: logs.reduce((s, d) => s + (d.book_pages || 0), 0),
  code_hrs: logs.reduce((s, d) => s + parseFloat(d.code_hrs || 0), 0),
  proposals_sent: logs.reduce((s, d) => s + (d.proposals_sent || 0), 0),
  revenue_earned: logs.reduce((s, d) => s + parseFloat(d.revenue_today || 0), 0),
  videos_published: logs.reduce((s, d) => s + (d.videos_published || 0), 0),
  avg_score: logs.length ? Math.round(logs.reduce((s, d) => s + (d.day_score || 0), 0) / logs.length) : 0,
  perfect_days: logs.filter(d => (d.day_score || 0) >= 90).length
};
return [{ json: { ...prev, stats } }];

const stats = $('Weekly Stats').first().json.stats;
const msg = `Week ${stats.week_number} report. Avg score: ${stats.avg_score}. Revenue: $${stats.revenue_earned}/$${stats.weekly_target}.`;
return [{ json: { choices: [{ message: { content: msg } }] } }];
